import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useNavigate } from 'react-router-dom'; // Added useNavigate import
import './App.css';
import LoginPage from './Components/Login';
import SignupPage from './Components/Signup';
import SideNav from './Components/SideNav'; // Import the SideNav component
import ChatBox from './Components/ChatBox';
import HomePage from './Components/HomePage'; // Import the HomePage component

// MainPage component (simplified)
function MainPage() {
  return (
    <div>
      <h2>Welcome to the Main Page</h2>
      {/* No logout button here anymore */}
    </div>
  );
}

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false); // Manage login state
  const navigate = useNavigate(); // Initialize the navigate function

  // Handle login success (simulate login in this case)
  const login = () => {
    setIsAuthenticated(true);
    navigate('/HomePage'); // Redirect to HomePage after login
  };

  // Handle logout (simulate logout)
  const logout = () => {
    setIsAuthenticated(false);
  };

  return (
    <Router>
      <div className="App">
        <h1>J-Test</h1>

        {/* Render SideNav only if authenticated */}
        {isAuthenticated && <SideNav logout={logout} />} {/* Pass logout to SideNav */}

        <Routes>
          {/* Login Route */}
          <Route path="/Login" element={<LoginPage login={login} />} />
          {/* Signup Route */}
          <Route path="/Signup" element={<SignupPage />} />

          {/* HomePage Route */}
          <Route
            path="/HomePage"
            element={
              isAuthenticated ? (
                <HomePage />
              ) : (
                <Navigate to="/Login" />
              )
            }
          />

          {/* ChatBox Route - No authentication required anymore */}
          <Route path="/ChatBox" element={<ChatBox />} />

          {/* Default route */}
          <Route path="/" element={<Navigate to="/Login" />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
